import json
import pickle
from base64 import b64decode

def lambda_handler(event, context):
    # Decode the base64-encoded payload
    encoded_payload = event['body']
    decoded_payload = b64decode(encoded_payload)
    
    # Deserialize the payload using pickle
    try:
        user_actions = pickle.loads(decoded_payload)
    except (pickle.UnpicklingError, EOFError) as e:
        return {
            'statusCode': 400,
            'body': json.dumps({'error': 'Invalid payload'})
        }
    
    # Process the user actions
    for action in user_actions:
        process_action(action)
    
    return {
        'statusCode': 200,
        'body': json.dumps({'message': 'Actions processed successfully'})
    }

def process_action(action):
    # Placeholder function to process each action
    print(f"Processing action: {action}")